// helper to lookup 10^e using pre-computed tables for fast o(1) scaling
static inline simd_f128 _simd_f128_pow10_int(int e_val) {
    if (e_val < -308) {
        return simd_f128_from_double(0.0);
    }
    if (e_val > 308) {
        return simd_f128_from_double(INFINITY);
    }
    if (e_val < 0) {
        const double* raw = _simd_f128_pow10_neg_table[-e_val];
        return simd_f128_from_hi_lo(raw[0], raw[1]);
    } else {
        const double* raw = _simd_f128_pow10_pos_table[e_val];
        return simd_f128_from_hi_lo(raw[0], raw[1]);
    }
}

// helper to do case-insensitive comparison of 3 characters
static inline int _simd_f128_strncasecmp3(const char* s1, const char* s2) {
    for (int i = 0; i < 3; i++) {
        char c1 = s1[i];
        char c2 = s2[i];
        if (c1 >= 'A' && c1 <= 'Z') c1 = c1 - 'A' + 'a';
        if (c2 >= 'A' && c2 <= 'Z') c2 = c2 - 'A' + 'a';
        if (c1 != c2) return c1 - c2;
    }
    return 0;
}

// converts the number to a string buffer with a specific number of significant digits
void simd_f128_to_string_prec(char* buf, size_t buf_size, simd_f128 x, int digits) {
    if (buf == NULL || buf_size == 0) return;
    if (digits < 1) digits = 1;
    if (digits > 60) digits = 60; // clamp to reasonable max

    double hi, lo;
    simd_f128_extract(x, &hi, &lo);

    // format nan input to string
    if (_simd_f128_isnan_double(hi)) {
        snprintf(buf, buf_size, "nan");
        return;
    }
    // format positive/negative infinity to string
    if (_simd_f128_isinf_double(hi)) {
        snprintf(buf, buf_size, hi < 0 ? "-inf" : "inf");
        return;
    }

    // handle negative numbers by negating and prepending the sign
    int is_neg = 0;
    if (hi < 0.0 || (hi == 0.0 && lo < 0.0)) {
        is_neg = 1;
        simd_f128 zero = simd_f128_from_double(0.0);
        x = simd_f128_sub(zero, x);
        simd_f128_extract(x, &hi, &lo);
    }

    // separate the integer part: we use the scalar floor(hi) rather than
    // simd_f128_floor(x) here because the rounding correction below handles
    // the edge case where hi is exact integer but lo is negative.
    double int_part = floor(hi);
    if (hi == int_part && lo < 0.0) {
        int_part -= 1.0;
    }

    // check if scientific notation is required (very large or very small values)
    double hi_abs = fabs(hi);
    if (hi_abs > 0.0 && (hi_abs >= 1e15 || hi_abs < 1e-4)) {
        int exp_val = (int)floor(log10(hi_abs));
        
        // scale the number by 10^-exp_val iteratively to avoid overflow
        int shift_exp = -exp_val;
        simd_f128 scaled_x = x;
        if (shift_exp > 250) {
            scaled_x = simd_f128_mul(scaled_x, _simd_f128_pow10_int(250));
            shift_exp -= 250;
        } else if (shift_exp < -250) {
            scaled_x = simd_f128_mul(scaled_x, _simd_f128_pow10_int(-250));
            shift_exp += 250;
        }
        scaled_x = simd_f128_mul(scaled_x, _simd_f128_pow10_int(shift_exp));
        
        double s_hi, s_lo;
        simd_f128_extract(scaled_x, &s_hi, &s_lo);
        if (fabs(s_hi) >= 10.0) {
            scaled_x = simd_f128_div(scaled_x, simd_f128_from_double(10.0));
            exp_val++;
        } else if (fabs(s_hi) < 1.0) {
            scaled_x = simd_f128_mul(scaled_x, simd_f128_from_double(10.0));
            exp_val--;
        }
        
        simd_f128_extract(scaled_x, &hi, &lo);
        
        double s_int_part = floor(hi);
        if (hi == s_int_part && lo < 0.0) {
            s_int_part -= 1.0;
        }
        
        char s_int_buf[64];
        snprintf(s_int_buf, sizeof(s_int_buf), "%.0f", s_int_part);
        
        simd_f128 f_int = simd_f128_from_double(s_int_part);
        simd_f128 frac = simd_f128_sub(scaled_x, f_int);
        simd_f128 ten = simd_f128_from_double(10.0);
        
        char frac_buf[128] = {0};
        int frac_len = 0;
        
        // extract significand digits iteratively
        for (int i = 0; i < digits - 1; i++) {
            frac = simd_f128_mul(frac, ten);
            double f_hi, f_lo;
            simd_f128_extract(frac, &f_hi, &f_lo);
            
            double digit = floor(f_hi);
            if (f_hi == digit && f_lo < 0.0) {
                digit -= 1.0;
            }
            if (digit < 0.0) digit = 0.0;
            if (digit > 9.0) digit = 9.0;
            
            frac_buf[frac_len++] = (char)('0' + (int)digit);
            frac = simd_f128_sub(frac, simd_f128_from_double(digit));
        }
        frac_buf[frac_len] = '\0';
        
        snprintf(buf, buf_size, "%s%s.%se%+d", is_neg ? "-" : "", s_int_buf, frac_buf, exp_val);
        return;
    }

    char int_buf[128];
    snprintf(int_buf, sizeof(int_buf), "%.0f", int_part);
    int int_digits = (int_part == 0.0) ? 1 : (int)strlen(int_buf);

    // standard decimal representation format loop
    simd_f128 f_int = simd_f128_from_double(int_part);
    simd_f128 frac  = simd_f128_sub(x, f_int);
    simd_f128 ten   = simd_f128_from_double(10.0);

    char frac_buf[128] = {0};
    int frac_len = 0;
    
    // total digits to extract is digits - int_digits
    int frac_digits_to_extract = digits - int_digits;
    if (frac_digits_to_extract < 0) frac_digits_to_extract = 0;

    // multiply by 10, grab integer digit, subtract, repeat
    for (int i = 0; i < frac_digits_to_extract; i++) {
        frac = simd_f128_mul(frac, ten);
        
        double f_hi, f_lo;
        simd_f128_extract(frac, &f_hi, &f_lo);
        
        double digit = floor(f_hi); 
        if (f_hi == digit && f_lo < 0.0) {
            digit -= 1.0;
        }
        
        if (digit < 0.0) digit = 0.0;
        if (digit > 9.0) digit = 9.0;
        
        frac_buf[frac_len++] = (char)('0' + (int)digit);
        frac = simd_f128_sub(frac, simd_f128_from_double(digit));
    }
    frac_buf[frac_len] = '\0';

    // print the formatted sign, integer, and fractional parts
    if (frac_len > 0) {
        snprintf(buf, buf_size, "%s%s.%s", is_neg ? "-" : "", int_buf, frac_buf);
    } else {
        snprintf(buf, buf_size, "%s%s", is_neg ? "-" : "", int_buf);
    }
}

// converts the number to a string buffer (default 32 digits)
void simd_f128_to_string(char* buf, size_t buf_size, simd_f128 x) {
    simd_f128_to_string_prec(buf, buf_size, x, 32);
}

// parses a string representation into a 128-bit double-double number
simd_f128 simd_f128_from_string(const char* str) {
    simd_f128 res = simd_f128_from_double(0.0);
    if (!str) return res;

    // skip leading whitespace characters
    while (*str == ' ' || *str == '\t' || *str == '\n' || *str == '\r') str++;

    // parse sign of the number
    int is_neg = 0;
    if (*str == '-') {
        is_neg = 1;
        str++;
    } else if (*str == '+') {
        str++;
    }

    // parse special string literals (nan / inf) case-insensitively
    if (_simd_f128_strncasecmp3(str, "nan") == 0) {
        return simd_f128_from_double(NAN);
    }
    if (_simd_f128_strncasecmp3(str, "inf") == 0) {
        return simd_f128_from_double(is_neg ? -INFINITY : INFINITY);
    }

    simd_f128 ten = simd_f128_from_double(10.0);
    int frac_count = 0;
    int has_dot = 0;
    int digit_count = 0;

    // we limit to 35 significant digits to avoid precision loss and performance overhead
    while (*str) {
        if (*str >= '0' && *str <= '9') {
            double d = (double)(*str - '0');
            // skip leading zeros to preserve precision capacity
            if (digit_count == 0 && d == 0.0) {
                if (has_dot) frac_count++;
            } else if (digit_count < 35) {
                res = simd_f128_add(simd_f128_mul(res, ten), simd_f128_from_double(d));
                if (has_dot) frac_count++;
                digit_count++;
            } else {
                // we have enough precision, but we must track the magnitude
                if (!has_dot) frac_count--;
            }
            str++;
        } else if (*str == '.' && !has_dot) {
            has_dot = 1;
            str++;
        } else {
            break;
        }
    }

    int parsed_exp = 0;
    // parse scientific exponent part (e/E followed by optional sign and integer)
    if (*str == 'e' || *str == 'E') {
        str++;
        int exp_neg = 0;
        if (*str == '-') {
            exp_neg = 1;
            str++;
        } else if (*str == '+') {
            str++;
        }
        int exp_val = 0;
        while (*str >= '0' && *str <= '9') {
            // prevent signed integer overflow for extremely large exponents
            if (exp_val < 100000) {
                exp_val = exp_val * 10 + (*str - '0');
            }
            str++;
        }
        parsed_exp = exp_neg ? -exp_val : exp_val;
    }

    // combine parsed exponent and fraction count
    int final_exp = parsed_exp - frac_count;

    // apply exponent scaling in chunks of 300 to prevent intermediate overflow/underflow
    if (final_exp < 0) {
        int e = -final_exp;
        while (e > 300) {
            res = simd_f128_div(res, _simd_f128_pow10_int(300));
            e -= 300;
        }
        if (e > 0) res = simd_f128_div(res, _simd_f128_pow10_int(e));
    } else if (final_exp > 0) {
        int e = final_exp;
        while (e > 300) {
            res = simd_f128_mul(res, _simd_f128_pow10_int(300));
            e -= 300;
        }
        if (e > 0) res = simd_f128_mul(res, _simd_f128_pow10_int(e));
    }

    // negate the final result if negative sign was matched
    if (is_neg) {
        res = simd_f128_neg(res);
    }

    return res;
}

